import React, { useState, useEffect, useRef } from 'react';
import io from 'socket.io-client';
import './App.css';

const formatTime = (seconds) => {
  const m = Math.floor(seconds / 60).toString().padStart(2, '0');
  const s = (seconds % 60).toString().padStart(2, '0');
  return `${m}:${s}`;
};

function RecordingWave({ recording }) {
  const [tick, setTick] = useState(0);
  useEffect(() => {
    if (!recording) return;
    const id = setInterval(() => setTick((t) => t + 1), 80);
    return () => clearInterval(id);
  }, [recording]);

  return (
    <div className="recording-wave">
      {Array.from({ length: 14 }).map((_, i) => {
        const h = recording ? 5 + Math.abs(Math.sin((tick + i * 2.5) * 0.5)) * 18 : 5;
        return (
          <div key={i} className="wave-bar" style={{ height: h }} />
        );
      })}
    </div>
  );
}

function VoiceMessage({ audioData, duration }) {
  const audioRef = useRef(null);
  const [playing, setPlaying] = useState(false);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const el = audioRef.current;
    if (!el) return;
    const onEnded = () => { setPlaying(false); setProgress(0); };
    const onTime = () => {
      if (el.duration) setProgress((el.currentTime / el.duration) * 100);
    };
    el.addEventListener('ended', onEnded);
    el.addEventListener('timeupdate', onTime);
    return () => { el.removeEventListener('ended', onEnded); el.removeEventListener('timeupdate', onTime); };
  }, []);

  const toggle = () => {
    const el = audioRef.current;
    if (!el) return;
    if (playing) { el.pause(); setPlaying(false); }
    else { el.play(); setPlaying(true); }
  };

  return (
    <div className="voice-message">
      <audio ref={audioRef} src={audioData} />
      <button onClick={toggle} className="voice-play-btn">
        {playing ? '⏸' : '▶'}
      </button>
      <div className="voice-progress-bar">
        <div className="voice-progress-fill" style={{ width: `${progress}%` }} />
      </div>
      <span className="voice-duration">{formatTime(duration || 0)}</span>
    </div>
  );
}

function App() {
  const [socket, setSocket] = useState(null);
  const [status, setStatus] = useState('initial');
  const [messages, setMessages] = useState([]);
  const [inputValue, setInputValue] = useState('');
  const [partnerId, setPartnerId] = useState(null);

  // Voice recording states
  const [recording, setRecording] = useState(false);
  const [recSeconds, setRecSeconds] = useState(0);
  const [audioPreview, setAudioPreview] = useState(null); // { url, base64, duration }

  const messagesEndRef = useRef(null);
  const mediaRef = useRef(null);
  const chunksRef = useRef([]);
  const timerRef = useRef(null);

  useEffect(() => {
    const newSocket = io('http://localhost:5000', {
      reconnection: true,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
      reconnectionAttempts: 5
    });

    newSocket.on('connect', () => console.log('Connected to server'));

    newSocket.on('waiting', () => {
      setStatus('waiting');
      setMessages([]);
    });

    newSocket.on('chat-started', (data) => {
      setStatus('chatting');
      setPartnerId(data.partnerId);
      setMessages([{ type: 'system', text: '✅ Connected to a random user!' }]);
    });

    newSocket.on('receive-message', (data) => {
      if (data.isVoice) {
        setMessages(prev => [...prev, {
          type: 'received',
          isVoice: true,
          audioData: data.audioData,
          duration: data.duration,
          time: data.timestamp
        }]);
      } else {
        setMessages(prev => [...prev, {
          type: 'received',
          text: data.message,
          time: data.timestamp
        }]);
      }
    });

    newSocket.on('chat-ended', () => {
      setStatus('ended');
      setPartnerId(null);
    });

    setSocket(newSocket);
    return () => newSocket.close();
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const startChat = () => socket?.emit('start-chat');

  const sendMessage = () => {
    if (inputValue.trim() && socket && status === 'chatting') {
      setMessages(prev => [...prev, { type: 'sent', text: inputValue }]);
      socket.emit('send-message', { message: inputValue, isVoice: false });
      setInputValue('');
    }
  };

  const sendVoice = () => {
    if (!audioPreview || status !== 'chatting') return;
    const time = new Date().toLocaleTimeString();
    socket.emit('send-message', {
      audioData: audioPreview.base64,
      isVoice: true,
      duration: audioPreview.duration,
    });
    setMessages(prev => [...prev, {
      type: 'sent',
      isVoice: true,
      audioData: audioPreview.url,
      duration: audioPreview.duration,
      time,
    }]);
    setAudioPreview(null);
    setRecSeconds(0);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mr = new MediaRecorder(stream);
      mediaRef.current = mr;
      chunksRef.current = [];
      let secs = 0;

      mr.ondataavailable = (e) => chunksRef.current.push(e.data);
      mr.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const url = URL.createObjectURL(blob);
        const reader = new FileReader();
        reader.onload = () => setAudioPreview({ url, base64: reader.result, duration: secs });
        reader.readAsDataURL(blob);
        stream.getTracks().forEach((t) => t.stop());
      };

      mr.start();
      setRecording(true);
      setRecSeconds(0);
      timerRef.current = setInterval(() => { secs++; setRecSeconds(secs); }, 1000);
    } catch {
      alert('Microphone access denied.');
    }
  };

  const stopRecording = () => {
    mediaRef.current?.stop();
    clearInterval(timerRef.current);
    setRecording(false);
  };

  const cancelRecording = () => {
    if (mediaRef.current?.state === 'recording') {
      mediaRef.current.ondataavailable = null;
      mediaRef.current.onstop = null;
      mediaRef.current?.stop();
      mediaRef.current?.stream?.getTracks().forEach((t) => t.stop());
    }
    clearInterval(timerRef.current);
    setRecording(false);
    setAudioPreview(null);
    setRecSeconds(0);
  };

  const endChat = () => {
    socket?.emit('end-chat');
    setStatus('initial');
    setMessages([]);
    setPartnerId(null);
    cancelRecording();
  };

  const startNew = () => {
    setStatus('initial');
    setMessages([]);
    setPartnerId(null);
  };

  return (
    <div className="app">
      <header className="header">
        <h1>🎲 Random Chat</h1>
        <p>Connect with random strangers and have fun conversations!</p>
      </header>

      <div className="container">
        {status === 'initial' && (
          <div className="welcome">
            <div className="welcome-card">
              <h2>Welcome to Random Chat!</h2>
              <p>Meet and chat with random people from around the world.</p>
              <button onClick={startChat} className="btn btn-primary">
                Start Chatting 🚀
              </button>
            </div>
          </div>
        )}

        {status === 'waiting' && (
          <div className="waiting">
            <div className="spinner"></div>
            <p>Looking for a chat partner...</p>
          </div>
        )}

        {status === 'chatting' && (
          <div className="chat">
            <div className="chat-header">
              <h2>💬 Chat with User #{partnerId.slice(-5)}</h2>
              <button onClick={endChat} className="btn btn-danger">
                End Chat ✌️
              </button>
            </div>

            <div className="messages">
              {messages.map((msg, idx) => (
                <div key={idx} className={`message message-${msg.type}`}>
                  {msg.isVoice ? (
                    <VoiceMessage audioData={msg.audioData} duration={msg.duration} />
                  ) : (
                    msg.text
                  )}
                </div>
              ))}
              <div ref={messagesEndRef} />
            </div>

            {/* Audio Preview Bar */}
            {audioPreview && !recording && (
              <div className="audio-preview">
                <span>🎤</span>
                <VoiceMessage audioData={audioPreview.url} duration={audioPreview.duration} />
                <button onClick={() => setAudioPreview(null)} className="cancel-audio-btn">✕</button>
              </div>
            )}

            <div className="input-area">
              <div className="input-row">
              {recording ? (
                /* Recording state */
                <div className="recording-bar">
                  <button onClick={cancelRecording} className="cancel-rec-btn">✕</button>
                  <div className="rec-dot" />
                  <RecordingWave recording={recording} />
                  <span className="rec-timer">{formatTime(recSeconds)}</span>
                </div>
              ) : (
                /* Normal text input */
                <input
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
                  placeholder="Type a message..."
                  className="input"
                />
              )}

              {/* Action buttons */}
              {audioPreview && !recording ? (
                /* Send voice */
                <button onClick={sendVoice} className="btn btn-send">Send 🎤</button>
              ) : recording ? (
                /* Stop recording */
                <button onClick={stopRecording} className="btn btn-mic recording">
                  <div className="stop-icon" />
                </button>
              ) : inputValue.trim() ? (
                /* Send text */
                <button onClick={sendMessage} className="btn btn-send">Send 📤</button>
              ) : (
                /* Mic button */
                <button onClick={startRecording} className="btn btn-mic">
                  🎤
                </button>
              )}
              </div>
            </div>
          </div>
        )}

        {status === 'ended' && (
          <div className="ended">
            <div className="ended-card">
              <h2>Chat Ended 👋</h2>
              <p>Thanks for chatting! Would you like to meet another random user?</p>
              <button onClick={startNew} className="btn btn-primary">
                Chat Again 🔄
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
